class Solution:
    def flipLights(self, n: int, presses: int) -> int:
        n = min(n, 3)
        if presses == 0:
            return 1
        elif presses == 1:
            return [2, 3, 4][n - 1]
        elif presses == 2:
            return [4, 7, 8][n - 1]
        else:
            return [8, 16, 16][n - 1]
```

